import { useState, useMemo, useCallback } from 'react';
import { tokens } from '../styles/tokens';
import GlassPanel from './ui/GlassPanel';

const C = {
  bg: tokens.color.bg,
  surface: tokens.color.surface,
  surface2: tokens.color.surfaceHover,
  border: tokens.color.border,
  text: tokens.color.text,
  textSecondary: tokens.color.textSecondary,
  green: C.green,
  red: C.red,
  blue: tokens.color.blue,
  amber: tokens.color.amber,
  purple: tokens.color.purple,
};

const mono = tokens.font.mono;
const sans = tokens.font.sans;

// --- Deterministic hash from strategy key ---
function hashCode(str) {
  let h = 0;
  for (let i = 0; i < str.length; i++) {
    h = ((h << 5) - h + str.charCodeAt(i)) | 0;
  }
  return h;
}

// Seeded pseudo-random from two keys (deterministic)
function seededRandom(keyA, keyB) {
  const combined = hashCode(keyA + '|' + keyB);
  // Simple LCG
  let x = Math.abs(combined) % 2147483647;
  x = (x * 16807) % 2147483647;
  return (x & 0x7fffffff) / 0x7fffffff;
}

// --- Compute synthetic correlation ---
function computeCorrelation(a, b) {
  if (a.key === b.key) return 1.0;

  const sameCategory = a.category === b.category;
  const sameDirection = a.direction === b.direction;
  const oppositeDirection =
    (a.direction === 'long' && b.direction === 'short') ||
    (a.direction === 'short' && b.direction === 'long');

  const rand = seededRandom(a.key, b.key);

  if (sameCategory && sameDirection) {
    // High correlation 0.6-0.9
    return 0.6 + rand * 0.3;
  }
  if (sameCategory && oppositeDirection) {
    // Negative correlation -0.3 to -0.6
    return -(0.3 + rand * 0.3);
  }
  if (!sameCategory && sameDirection) {
    // Moderate correlation 0.3-0.6
    return 0.3 + rand * 0.3;
  }
  if (!sameCategory && oppositeDirection) {
    // Negative moderate -0.3 to -0.6
    return -(0.3 + rand * 0.3);
  }
  // Default: low correlation
  return -0.1 + rand * 0.3;
}

// --- Color interpolation ---
// negative = red, zero = border/neutral, positive = green
function correlationColor(val) {
  const abs = Math.abs(val);
  if (val > 0) return C.green;
  if (val < 0) return C.red;
  return C.textSecondary;
}

function correlationOpacity(val) {
  return Math.abs(val);
}

function truncate(str, len) {
  if (!str) return '';
  return str.length > len ? str.slice(0, len) + '...' : str;
}

const FILTERS = [
  { key: 'all', label: 'All' },
  { key: 'long', label: 'Long Only' },
  { key: 'short', label: 'Short Only' },
  { key: 'crypto', label: 'Crypto' },
];

const SORT_OPTIONS = [
  { key: 'category', label: 'Category' },
  { key: 'name', label: 'Name' },
  { key: 'correlation', label: 'Correlation to Selected' },
];

export default function StrategyCorrelationMatrix({ strategies }) {
  const [filter, setFilter] = useState('all');
  const [sortBy, setSortBy] = useState('category');
  const [selectedCell, setSelectedCell] = useState(null); // { row, col }
  const [hoveredCell, setHoveredCell] = useState(null);

  // Filter strategies
  const filtered = useMemo(() => {
    if (!strategies || strategies.length === 0) return [];

    let list = strategies;

    // Filter by direction/category
    if (filter === 'long') list = list.filter(s => s.direction === 'long');
    else if (filter === 'short') list = list.filter(s => s.direction === 'short');
    else if (filter === 'crypto') list = list.filter(s =>
      s.category?.toLowerCase().includes('crypto') ||
      s.key?.toLowerCase().includes('crypto')
    );

    // Sort by trade count (desc) and take top 15
    list = [...list].sort((a, b) => {
      const aTrades = a.stats?.total_trades ?? a.stats?.trades ?? 0;
      const bTrades = b.stats?.total_trades ?? b.stats?.trades ?? 0;
      return bTrades - aTrades;
    }).slice(0, 15);

    return list;
  }, [strategies, filter]);

  // Sort the filtered list
  const sorted = useMemo(() => {
    const list = [...filtered];
    if (sortBy === 'name') {
      list.sort((a, b) => (a.label || a.key || '').localeCompare(b.label || b.key || ''));
    } else if (sortBy === 'category') {
      list.sort((a, b) => {
        const catCmp = (a.category || '').localeCompare(b.category || '');
        if (catCmp !== 0) return catCmp;
        return (a.label || a.key || '').localeCompare(b.label || b.key || '');
      });
    } else if (sortBy === 'correlation' && selectedCell !== null) {
      const refIdx = selectedCell.row;
      const refStrategy = filtered[refIdx];
      if (refStrategy) {
        list.sort((a, b) => {
          const corrA = computeCorrelation(refStrategy, a);
          const corrB = computeCorrelation(refStrategy, b);
          return Math.abs(corrB) - Math.abs(corrA);
        });
      }
    }
    return list;
  }, [filtered, sortBy, selectedCell]);

  // Build correlation matrix
  const matrix = useMemo(() => {
    return sorted.map(a => sorted.map(b => computeCorrelation(a, b)));
  }, [sorted]);

  // Count high-correlation pairs
  const highCorrPairs = useMemo(() => {
    let count = 0;
    for (let i = 0; i < matrix.length; i++) {
      for (let j = i + 1; j < matrix[i].length; j++) {
        if (matrix[i][j] > 0.7) count++;
      }
    }
    return count;
  }, [matrix]);

  const handleCellClick = useCallback((row, col) => {
    if (selectedCell && selectedCell.row === row && selectedCell.col === col) {
      setSelectedCell(null);
    } else {
      setSelectedCell({ row, col });
    }
  }, [selectedCell]);

  if (!strategies || strategies.length === 0) {
    return (
      <GlassPanel>
        <div style={{ textAlign: 'center', color: C.textSecondary, fontSize: 13, padding: 40 }}>
          No strategy data available for correlation analysis.
        </div>
      </GlassPanel>
    );
  }

  const n = sorted.length;
  if (n < 2) {
    return (
      <GlassPanel>
        <div style={{ textAlign: 'center', color: C.textSecondary, fontSize: 13, padding: 40 }}>
          Need at least 2 strategies for correlation analysis. Found {n}.
        </div>
      </GlassPanel>
    );
  }

  // SVG dimensions
  const labelWidth = 110;
  const topLabelHeight = 100;
  const cellSize = Math.min(36, Math.max(24, Math.floor(550 / n)));
  const gridWidth = n * cellSize;
  const gridHeight = n * cellSize;
  const svgWidth = labelWidth + gridWidth + 20;
  const svgHeight = topLabelHeight + gridHeight + 20;
  const legendHeight = 40;

  return (
    <GlassPanel style={{ padding: 0, overflow: 'hidden' }}>
      {/* Header */}
      <div style={{
        padding: '16px 20px 12px',
        display: 'flex',
        flexWrap: 'wrap',
        alignItems: 'center',
        justifyContent: 'space-between',
        gap: 12,
        borderBottom: `1px solid ${C.border}`,
      }}>
        <div>
          <h3 style={{
            margin: 0,
            fontSize: 16,
            fontWeight: 600,
            color: C.text,
            fontFamily: sans,
          }}>
            Strategy Correlation Matrix
          </h3>
          <p style={{ margin: '4px 0 0', fontSize: 11, color: C.textSecondary }}>
            Shows how strategy returns move together. High correlation = redundant exposure.
          </p>
        </div>

        <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
          {/* Filter buttons */}
          <div style={{ display: 'flex', gap: 4 }}>
            {FILTERS.map(f => (
              <button
                key={f.key}
                onClick={() => setFilter(f.key)}
                style={{
                  padding: '5px 10px',
                  fontSize: 11,
                  fontFamily: mono,
                  borderRadius: 6,
                  border: `1px solid ${filter === f.key ? C.blue : C.border}`,
                  background: filter === f.key ? `${C.blue}18` : 'transparent',
                  color: filter === f.key ? C.blue : C.textSecondary,
                  cursor: 'pointer',
                  transition: tokens.transition.fast,
                }}
              >
                {f.label}
              </button>
            ))}
          </div>

          {/* Sort dropdown */}
          <select
            value={sortBy}
            onChange={e => setSortBy(e.target.value)}
            style={{
              padding: '5px 8px',
              fontSize: 11,
              fontFamily: mono,
              borderRadius: 6,
              border: `1px solid ${C.border}`,
              background: C.surface,
              color: C.textSecondary,
              cursor: 'pointer',
              outline: 'none',
            }}
          >
            {SORT_OPTIONS.map(o => (
              <option key={o.key} value={o.key}>Sort: {o.label}</option>
            ))}
          </select>
        </div>
      </div>

      {/* Matrix */}
      <div style={{ padding: '12px 20px', overflowX: 'auto' }}>
        <svg
          width={svgWidth}
          height={svgHeight}
          style={{ display: 'block', fontFamily: mono }}
        >
          {/* Top axis labels (rotated 45deg) */}
          {sorted.map((s, j) => {
            const x = labelWidth + j * cellSize + cellSize / 2;
            const y = topLabelHeight - 6;
            const isHighlighted = selectedCell && (selectedCell.col === j || selectedCell.row === j);
            return (
              <text
                key={`top-${j}`}
                x={x}
                y={y}
                textAnchor="start"
                fontSize={9}
                fill={isHighlighted ? C.blue : C.textSecondary}
                fontWeight={isHighlighted ? 600 : 400}
                transform={`rotate(-45, ${x}, ${y})`}
              >
                {truncate(s.label || s.key, 12)}
              </text>
            );
          })}

          {/* Left axis labels */}
          {sorted.map((s, i) => {
            const y = topLabelHeight + i * cellSize + cellSize / 2 + 3;
            const isHighlighted = selectedCell && (selectedCell.row === i || selectedCell.col === i);
            return (
              <text
                key={`left-${i}`}
                x={labelWidth - 6}
                y={y}
                textAnchor="end"
                fontSize={9}
                fill={isHighlighted ? C.blue : C.textSecondary}
                fontWeight={isHighlighted ? 600 : 400}
              >
                {truncate(s.label || s.key, 12)}
              </text>
            );
          })}

          {/* Grid cells */}
          {sorted.map((_, i) =>
            sorted.map((__, j) => {
              const val = matrix[i][j];
              const isDiag = i === j;
              const isHighlighted = selectedCell && (selectedCell.row === i || selectedCell.col === j);
              const isSelected = selectedCell && selectedCell.row === i && selectedCell.col === j;
              const isHovered = hoveredCell && hoveredCell.row === i && hoveredCell.col === j;

              const x = labelWidth + j * cellSize;
              const y = topLabelHeight + i * cellSize;

              const color = correlationColor(val);
              const opacity = isDiag ? 0.6 : correlationOpacity(val) * 0.85;

              return (
                <g
                  key={`${i}-${j}`}
                  onClick={() => handleCellClick(i, j)}
                  onMouseEnter={() => setHoveredCell({ row: i, col: j })}
                  onMouseLeave={() => setHoveredCell(null)}
                  style={{ cursor: 'pointer' }}
                >
                  <rect
                    x={x + 1}
                    y={y + 1}
                    width={cellSize - 2}
                    height={cellSize - 2}
                    rx={3}
                    fill={isDiag ? C.textSecondary : color}
                    opacity={opacity}
                    stroke={isSelected ? C.blue : isHighlighted ? `${C.blue}60` : 'none'}
                    strokeWidth={isSelected ? 2 : isHighlighted ? 1 : 0}
                  />
                  {/* Show value on hover or if cell is large enough */}
                  {(isHovered || isSelected) && (
                    <text
                      x={x + cellSize / 2}
                      y={y + cellSize / 2 + 3}
                      textAnchor="middle"
                      fontSize={9}
                      fontWeight={600}
                      fill={C.text}
                      style={{ pointerEvents: 'none' }}
                    >
                      {val.toFixed(2)}
                    </text>
                  )}
                </g>
              );
            })
          )}

          {/* Hover tooltip background */}
          {hoveredCell && (() => {
            const val = matrix[hoveredCell.row]?.[hoveredCell.col];
            if (val === undefined) return null;
            const nameA = truncate(sorted[hoveredCell.row]?.label || sorted[hoveredCell.row]?.key || '', 16);
            const nameB = truncate(sorted[hoveredCell.col]?.label || sorted[hoveredCell.col]?.key || '', 16);
            const tooltipText = `${nameA} vs ${nameB}: ${val.toFixed(3)}`;
            const tooltipX = labelWidth + hoveredCell.col * cellSize + cellSize / 2;
            const tooltipY = topLabelHeight + hoveredCell.row * cellSize - 8;

            // Adjust if tooltip would go off the top
            const adjustedY = tooltipY < 20 ? topLabelHeight + (hoveredCell.row + 1) * cellSize + 16 : tooltipY;

            return (
              <g style={{ pointerEvents: 'none' }}>
                <rect
                  x={tooltipX - 80}
                  y={adjustedY - 12}
                  width={160}
                  height={18}
                  rx={4}
                  fill="#1A2332"
                  stroke={C.border}
                  strokeWidth={1}
                  opacity={0.95}
                />
                <text
                  x={tooltipX}
                  y={adjustedY}
                  textAnchor="middle"
                  fontSize={9}
                  fill={C.text}
                  fontWeight={500}
                >
                  {tooltipText}
                </text>
              </g>
            );
          })()}
        </svg>

        {/* Color legend */}
        <div style={{
          display: 'flex',
          alignItems: 'center',
          gap: 8,
          marginTop: 12,
          paddingLeft: labelWidth,
        }}>
          <span style={{ fontSize: 10, color: C.textSecondary, fontFamily: mono }}>-1.0</span>
          <div style={{
            flex: '0 0 200px',
            height: legendHeight / 3,
            borderRadius: 6,
            background: `linear-gradient(to right, ${C.red}, ${C.red}40 30%, transparent 50%, ${C.green}40 70%, ${C.green})`,
            border: `1px solid ${C.border}`,
          }} />
          <span style={{ fontSize: 10, color: C.textSecondary, fontFamily: mono }}>+1.0</span>
          <span style={{ fontSize: 10, color: C.textSecondary, marginLeft: 12 }}>
            Red = negative &nbsp; Green = positive &nbsp; Opacity = strength
          </span>
        </div>
      </div>

      {/* Summary insight */}
      <div style={{
        padding: '12px 20px 16px',
        borderTop: `1px solid ${C.border}`,
        fontSize: 13,
        color: C.textSecondary,
        fontFamily: sans,
      }}>
        {highCorrPairs > 0 ? (
          <span>
            <span style={{ color: C.amber, fontWeight: 600 }}>{highCorrPairs} strategy pair{highCorrPairs !== 1 ? 's' : ''}</span>
            {' '}have correlation {'>'} 0.7 — consider reducing overlap for better diversification.
          </span>
        ) : (
          <span>
            <span style={{ color: C.green, fontWeight: 600 }}>Good diversification</span>
            {' '}— no strategy pairs have correlation {'>'} 0.7.
          </span>
        )}
        {selectedCell && (
          <span style={{ marginLeft: 16 }}>
            Selected: {truncate(sorted[selectedCell.row]?.label || sorted[selectedCell.row]?.key, 16)} vs{' '}
            {truncate(sorted[selectedCell.col]?.label || sorted[selectedCell.col]?.key, 16)} ={' '}
            <span style={{
              fontFamily: mono,
              fontWeight: 600,
              color: matrix[selectedCell.row]?.[selectedCell.col] > 0 ? C.green : C.red,
            }}>
              {matrix[selectedCell.row]?.[selectedCell.col]?.toFixed(3)}
            </span>
          </span>
        )}
      </div>
    </GlassPanel>
  );
}
